import{_ as t,o as a,c as o,a2 as n}from"./chunks/framework.ufzXw1qY.js";const u=JSON.parse('{"title":"Vercel Deployment","description":"","frontmatter":{"title":"Vercel Deployment"},"headers":[],"relativePath":"guide/vercel-deployment.md","filePath":"guide/vercel-deployment.md"}'),i={name:"guide/vercel-deployment.md"};function r(l,e,s,d,c,p){return a(),o("div",null,[...e[0]||(e[0]=[n('<h1 id="vercel-deployment" tabindex="-1">Vercel Deployment <a class="header-anchor" href="#vercel-deployment" aria-label="Permalink to &quot;Vercel Deployment&quot;">​</a></h1><p>This page documents the Vercel-hosted OpenSIN surfaces that are part of the current public product model. It is intentionally scoped to public-safe, verified information only.</p><div class="important custom-block github-alert"><p class="custom-block-title">IMPORTANT</p><p>Source of truth for repo ownership and deployed surfaces is <a href="https://github.com/OpenSIN-AI/OpenSIN-overview/blob/main/docs/CANONICAL-REPOS.md" target="_blank" rel="noreferrer"><code>OpenSIN-overview/docs/CANONICAL-REPOS.md</code></a>. If this page and that file disagree, <code>OpenSIN-overview</code> wins.</p></div><h2 id="verified-surface-mapping" tabindex="-1">Verified Surface Mapping <a class="header-anchor" href="#verified-surface-mapping" aria-label="Permalink to &quot;Verified Surface Mapping&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Domain</th><th>Canonical Repo</th><th>Role</th><th>Platform</th></tr></thead><tbody><tr><td><code>chat.opensin.ai</code></td><td><a href="https://github.com/OpenSIN-AI/OpenSIN-WebApp" target="_blank" rel="noreferrer"><code>OpenSIN-WebApp</code></a></td><td>Authenticated dashboard, fleet control, chat</td><td>Vercel</td></tr><tr><td><code>my.opensin.ai</code></td><td><a href="https://github.com/OpenSIN-AI/website-my.opensin.ai" target="_blank" rel="noreferrer"><code>website-my.opensin.ai</code></a></td><td>Paid-layer marketing and marketplace</td><td>Vercel</td></tr></tbody></table><div class="note custom-block github-alert"><p class="custom-block-title">NOTE</p><p><code>docs.opensin.ai</code> is not deployed on Vercel. The documentation site is hosted separately and documented in the <a href="/governance/domain-registry.html">Domain Registry</a>.</p></div><h2 id="what-belongs-on-vercel" tabindex="-1">What Belongs On Vercel <a class="header-anchor" href="#what-belongs-on-vercel" aria-label="Permalink to &quot;What Belongs On Vercel&quot;">​</a></h2><p>OpenSIN uses Vercel for web properties that need fast frontend delivery and, in the case of <code>chat.opensin.ai</code>, authenticated application routing.</p><h3 id="chat-opensin-ai" tabindex="-1"><code>chat.opensin.ai</code> <a class="header-anchor" href="#chat-opensin-ai" aria-label="Permalink to &quot;`chat.opensin.ai`&quot;">​</a></h3><ul><li>Repo: <a href="https://github.com/OpenSIN-AI/OpenSIN-WebApp" target="_blank" rel="noreferrer"><code>OpenSIN-WebApp</code></a></li><li>Package name: <code>opensin-chat</code></li><li>Stack: Next.js 16 + Supabase</li><li>Purpose: logged-in user surface for dashboard, fleet control, billing-adjacent actions, and agent interaction</li></ul><h3 id="my-opensin-ai" tabindex="-1"><code>my.opensin.ai</code> <a class="header-anchor" href="#my-opensin-ai" aria-label="Permalink to &quot;`my.opensin.ai`&quot;">​</a></h3><ul><li>Repo: <a href="https://github.com/OpenSIN-AI/website-my.opensin.ai" target="_blank" rel="noreferrer"><code>website-my.opensin.ai</code></a></li><li>Stack: static marketing / marketplace surface</li><li>Purpose: plans, bundles, conversion funnel, and premium-layer positioning</li></ul><h2 id="what-does-not-belong-here" tabindex="-1">What Does Not Belong Here <a class="header-anchor" href="#what-does-not-belong-here" aria-label="Permalink to &quot;What Does Not Belong Here&quot;">​</a></h2><p>This page does not track:</p><ul><li>unrelated Vercel projects from other businesses or old personal orgs</li><li>internal project IDs that are not required for public operation</li><li>speculative domains or in-progress experiments without canonical ownership</li></ul><p>If you need internal deployment runbooks, credentials, or project-level secret handling, that information belongs in the private infrastructure repos, not in public docs.</p><h2 id="deployment-model" tabindex="-1">Deployment Model <a class="header-anchor" href="#deployment-model" aria-label="Permalink to &quot;Deployment Model&quot;">​</a></h2><p>For the public-facing Vercel surfaces, the expected production flow is:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>git push -&gt; Vercel build -&gt; deployment preview -&gt; production promotion</span></span></code></pre></div><p>The exact CI/CD contract for the org is tracked in <code>OpenSIN-overview</code>, which documents that self-hosted automation is the canonical CI layer and that public surface repos consume those contracts instead of inventing their own.</p><h2 id="environment-notes" tabindex="-1">Environment Notes <a class="header-anchor" href="#environment-notes" aria-label="Permalink to &quot;Environment Notes&quot;">​</a></h2><p>Public docs should only reference environment variables that matter to the surface contract. For example, <code>chat.opensin.ai</code> depends on backend/auth endpoints exposed by the backend control plane, but this page intentionally does not duplicate secret or internal-only deployment values.</p><h2 id="related" tabindex="-1">Related <a class="header-anchor" href="#related" aria-label="Permalink to &quot;Related&quot;">​</a></h2><ul><li><a href="/governance/domain-registry.html">Domain Registry</a></li><li><a href="/guide/opensin-ai-overview.html">OpenSIN-AI Overview</a></li><li><a href="/guide/deployment.html">Deployment Guide</a></li></ul>',24)])])}const m=t(i,[["render",r]]);export{u as __pageData,m as default};
